 88→func TestHMACValidator_RSASignedToken(t *testing.T) {
 89→	// An HS256 validator should reject tokens signed with a different method.
 90→	// We simulate this by creating a token that claims RS256 but is actually nonsense.
 91→	token := jwt.NewWithClaims(jwt.SigningMethodHS256, &Claims{
 92→		RegisteredClaims: jwt.RegisteredClaims{
 93→			ExpiresAt: jwt.NewNumericDate(time.Now().Add(time.Hour)),
 94→		},
