146→// Item is the resolver for the item field.
147→func (r *queryResolver) Item(ctx context.Context, id string) (*model.Item, error) {
148→	claims, err := requireAuth(ctx)
149→	if err != nil {
150→		return nil, err
151→	}
152→
153→	itemID, err := uuid.Parse(id)
154→	if err != nil {
155→		return nil, fmt.Errorf("resolver: invalid item id: %w", err)
156→	}
157→
158→	it, err := r.ItemService.GetByID(ctx, claims.UserID, itemID)
159→	if err != nil {
160→		return nil, fmt.Errorf("resolver: item: %w", err)
161→	}
162→	if it == nil {
163→		return nil, nil
164→	}
165→	return toGraphQLItem(it), nil
166→}
