168→// Items is the resolver for the items field.
169→func (r *queryResolver) Items(ctx context.Context, filter *model.ItemFilter, limit *int, offset *int, sort *model.ItemSort) (*model.SearchResult, error) {
170→	claims, err := requireAuth(ctx)
171→	if err != nil {
172→		return nil, err
173→	}
174→
175→	result, err := r.ItemService.List(ctx, claims.UserID,
176→		toItemFilter(filter),
177→		derefIntOr(limit, 20),
178→		derefIntOr(offset, 0),
179→		toItemSort(sort))
180→	if err != nil {
181→		return nil, fmt.Errorf("resolver: items: %w", err)
182→	}
183→
184→	return &model.SearchResult{
185→		Items:   toGraphQLItems(result.Items),
186→		Total:   result.Total,
187→		HasMore: result.HasMore,
188→	}, nil
189→}
190→
191→// Search is the resolver for the search field.
192→func (r *queryResolver) Search(ctx context.Context, query string, filter *model.ItemFilter, limit *int, threshold *float64) (*model.SearchResult, error) {
193→	claims, err := requireAuth(ctx)
194→	if err != nil {
195→		return nil, err
196→	}
197→
198→	result, err := r.ItemService.Search(ctx, claims.UserID, query,
199→		toItemFilter(filter),
200→		derefIntOr(limit, 20),
201→		derefFloat64Or(threshold, 0.0))
202→	if err != nil {
203→		return nil, fmt.Errorf("resolver: search: %w", err)
204→	}
205→
206→	return &model.SearchResult{
207→		Items:   toGraphQLItems(result.Items),
208→		Total:   result.Total,
209→		HasMore: result.HasMore,
210→	}, nil
211→}
