 13→var errAuthRequired = errors.New("resolver: authentication required")
 14→
 15→// requireAuth extracts auth claims from context or returns an error.
 16→func requireAuth(ctx context.Context) (*auth.Claims, error) {
 17→	claims := auth.GetClaims(ctx)
 18→	if claims == nil {
 19→		return nil, errAuthRequired
 20→	}
 21→	return claims, nil
 22→}
