 24→// toGraphQLItem maps a domain Item to the GraphQL model Item.
 25→func toGraphQLItem(it *item.Item) *model.Item {
 26→	return &model.Item{
 27→		ID:           it.ID.String(),
 28→		Type:         model.ItemType(strings.ToUpper(it.Type)),
 29→		Status:       model.ItemStatus(strings.ToUpper(it.Status)),
 30→		Sensitivity:  model.SensitivityLevel(strings.ToUpper(it.Sensitivity)),
 31→		Title:        it.Title,
 32→		ContentText:  it.ContentText,
 33→		ContentURL:   it.ContentURL,
 34→		Tags:         ensureStringSlice(it.Tags),
 35→		Metadata:     ensureMap(it.Metadata),
 36→		AutoMetadata: ensureMap(it.AutoMetadata),
 37→		Source:       it.Source,
 38→		SourceURL:    it.SourceURL,
 39→		CreatedAt:    it.CreatedAt,
 40→		UpdatedAt:    it.UpdatedAt,
 41→		CapturedAt:   it.CapturedAt,
 42→	}
 43→}
 44→
 45→// toGraphQLItems maps a slice of domain Items to GraphQL model Items.
 46→func toGraphQLItems(items []*item.Item) []*model.Item {
 47→	result := make([]*model.Item, len(items))
 48→	for i, it := range items {
 49→		result[i] = toGraphQLItem(it)
 50→	}
 51→	return result
 52→}
