 54→// toItemFilter converts a GraphQL ItemFilter to a domain Filter.
 55→func toItemFilter(f *model.ItemFilter) *item.Filter {
 56→	if f == nil {
 57→		return nil
 58→	}
 59→	result := &item.Filter{
 60→		Source: f.Source,
 61→	}
 62→	for _, t := range f.Types {
 63→		result.Types = append(result.Types, strings.ToLower(string(t)))
 64→	}
 65→	for _, s := range f.Status {
 66→		result.Status = append(result.Status, strings.ToLower(string(s)))
 67→	}
 68→	for _, s := range f.Sensitivity {
 69→		result.Sensitivity = append(result.Sensitivity, strings.ToLower(string(s)))
 70→	}
 71→	result.Tags = f.Tags
 72→	if f.DateFrom != nil {
 73→		result.DateFrom = f.DateFrom
 74→	}
 75→	if f.DateTo != nil {
 76→		result.DateTo = f.DateTo
 77→	}
 78→	return result
 79→}
