 81→// toItemSort converts a GraphQL ItemSort to a domain Sort.
 82→func toItemSort(s *model.ItemSort) *item.Sort {
 83→	if s == nil {
 84→		return nil
 85→	}
 86→	return &item.Sort{
 87→		Field:     string(s.Field),
 88→		Direction: string(s.Direction),
 89→	}
 90→}
