 92→// sensitivityToString converts a GraphQL SensitivityLevel to lowercase DB string.
 93→// Returns "normal" if nil.
 94→func sensitivityToString(s *model.SensitivityLevel) string {
 95→	if s == nil {
 96→		return "normal"
 97→	}
 98→	return strings.ToLower(string(*s))
 99→}
